<div class="d-flex flex-wrap justify-content-between align-items-center gap-3 mb-4"><div><h1 class="h3 mb-1">Crew Performance</h1><p class="text-muted mb-0">Jobs, labor hours, revenue, and revenue per labor hour.</p></div><form class="d-flex gap-2"><input class="form-control" type="date" name="from" value="<?=e($from)?>"><input class="form-control" type="date" name="to" value="<?=e($to)?>"><button class="btn btn-primary">Run</button></form></div>
<div class="card"><div class="table-responsive"><table class="table mb-0"><thead><tr><th>Crew</th><th class="text-end">Jobs</th><th class="text-end">Labor hours</th><th class="text-end">Revenue</th><th class="text-end">Revenue/hour</th></tr></thead><tbody><?php foreach($rows as $row):?><?php $rph=(float)$row['labor_hours']>0?(float)$row['revenue']/(float)$row['labor_hours']:0;?><tr><td><?=e($row['name'])?></td><td class="text-end"><?=(int)$row['jobs']?></td><td class="text-end"><?=number_format((float)$row['labor_hours'],1)?></td><td class="text-end">$<?=number_format((float)$row['revenue'],2)?></td><td class="text-end">$<?=number_format($rph,2)?></td></tr><?php endforeach?><?php if(!$rows):?><tr><td colspan="5" class="text-center text-muted py-4">No crew activity in this period.</td></tr><?php endif?></tbody></table></div></div>
